import React, { useEffect, useState } from "react";
import JournalCard from "./JournalCard";

const History = ({ onEditEntry }) => {
  const [entries, setEntries] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
    setEntries(stored.reverse());
  }, []);

  const handleDelete = (id) => {
    if (window.confirm("Are you sure you want to delete this entry?")) {
      const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
      const filtered = stored.filter((e) => e.id !== id);
      localStorage.setItem("journalEntries", JSON.stringify(filtered));
      setEntries(filtered.reverse());
    }
  };

  return (
    <div className="history-page">
      <h1 className="history-heading">Journal History</h1>
      <div className="history-list">
        {entries.length > 0 ? (
          entries.map((entry) => (
            <JournalCard
              key={entry.id}
              id={entry.id}
              title={entry.title}
              date={entry.date}
              entry={entry.entry}
              analyzed={entry.analyzed}
              analysis={entry.analysis}
              onEdit={onEditEntry}
              onDelete={handleDelete}
            />
          ))
        ) : (
          <p>No journal entries found.</p>
        )}
      </div>
      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => {
  <style>{`
        .history-page {
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          padding: 1rem;
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        .history-heading {
          font-size: 2.5rem;
          margin-bottom: 2rem;
        }

        .history-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          gap: 1rem;
          width: 100%;
          max-width: 1200px;
        }

        @media (max-width: 600px) {
          .history-heading {
            font-size: 2rem;
          }
        }
      `}</style>
}
export default History;
